UPDATE com.tn_sys_authrt_prgrm_mpng
   SET inq_authrt_yn   = #{inqAuthrtYn},
       inpt_authrt_yn  = #{inptAuthrtYn},
       last_chg_dt     = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE authrt_id = #{authrtId}
   AND prgrm_id  = #{prgrmId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE com.tn_sys_authrt_prgrm_mpng
   SET use_end_dt      = NOW() - INTERVAL '1 minute',
       last_chg_dt     = NOW(),
       last_chg_user_id = #{userId}
 WHERE authrt_id = #{authrtId}
   AND prgrm_id  = #{prgrmId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
